$(document).ready(function(){$('#id_assigned_to').select2({theme:'bootstrap-5',language:'ru',placeholder:'Выберите исполнителей...',allowClear:true,width:'100%'});document.getElementById('tzFileInput').addEventListener('change',function(e){const fileInfo=document.getElementById('fileInfo');const fileName=document.getElementById('fileName');if(this.files.length>0){if(fileInfo)fileInfo.style.display='block';if(fileName)fileName.textContent=this.files[0].name;const titleField=document.getElementById('id_title');if(titleField&&!titleField.value){titleField.placeholder='Будет взято из ТЗ';}}else{if(fileInfo)fileInfo.style.display='none';}});});;